  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `pass` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `file1` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `recommend_num` int DEFAULT '0',
  PRIMARY KEY (`contest_no`)
