LOCK TABLES `faq` WRITE;
/*!40000 ALTER TABLE `faq` DISABLE KEYS */;
INSERT INTO `faq` VALUES (1,'이 사이트는 어떤 목적으로 만들어졌나요?','개발자들이 코딩 테스트 문제와 노하우를 공유하고, 협업할 수 있도록 돕기 위해 만들어졌습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(2,'회원 가입은 어떻게 하나요?','상단 메뉴에서 회원 가입 버튼을 클릭해 이메일과 비밀번호를 입력하면 가입할 수 있습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(3,'AI 코딩 문제 풀이 지원 기능은 어떻게 사용하나요?','문제 풀이 페이지에서 질문을 입력하면 AI가 풀이 예제와 설명을 제공합니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(4,'내 작업물을 어떻게 저장하고 관리할 수 있나요?','개인 다이어리 기능과 Git 연동을 통해 버전 관리하며 저장할 수 있습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(5,'코딩 작업용 음악 플레이리스트는 어떻게 활성화하나요?','개인 도구 메뉴에서 플레이리스트 탭을 선택해 원하는 음악을 재생할 수 있습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(6,'문제 풀이 중 모르는 내용이 있으면 어디서 질문하나요?','커뮤니티 게시판에 질문글을 작성하거나, 댓글로 다른 사용자와 소통할 수 있습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(7,'프로젝트 협업 기능은 무엇인가요?','팀원들과 작업을 분담하고 진행 상황을 공유하는 협업 도구를 제공합니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(8,'포인트는 어떻게 획득하나요?','문제 풀이 완료, 게시글 작성, 다른 사용자 도움 등 다양한 활동으로 포인트를 받을 수 있습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(9,'포인트는 어디에 사용할 수 있나요?','포인트는 사이트 내 특별 콘텐츠 접근, 아이템 구매 등 다양한 용도로 활용할 수 있습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(10,'비밀번호를 잊어버렸을 때 어떻게 하나요?','로그인 페이지에서 ‘비밀번호 찾기’ 기능을 통해 이메일 인증 후 재설정할 수 있습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(11,'모바일에서도 사이트를 사용할 수 있나요?','네, 모바일 최적화가 되어 있어 스마트폰과 태블릿에서도 편리하게 이용할 수 있습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(12,'내 프로필 정보는 어떻게 수정하나요?','로그인 후 마이페이지에서 닉네임, 이메일 등 프로필 정보를 변경할 수 있습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18'),(13,'사이트 이용 중 오류가 발생하면 어떻게 신고하나요?','고객센터 또는 피드백 메뉴를 통해 상세 내용을 작성해 보내주시면 빠르게 처리하겠습니다.','2025-08-18 00:35:18','2025-08-18 00:35:18');
/*!40000 ALTER TABLE `faq` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `lecture`
