DROP TABLE IF EXISTS `pointlog`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pointlog` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '로그 ID (PK)',
  `user_id` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '사용자 ID (FK)',
  `points` int DEFAULT NULL COMMENT '지급 또는 사용된 포인트',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '포인트 변경 사유',
  `eventType` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '포인트 변경 이벤트 타입',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '로그 생성 시각',
  PRIMARY KEY (`id`),
  KEY `fk_pointlog_user` (`user_id`),
  CONSTRAINT `fk_pointlog_user` FOREIGN KEY (`user_id`) REFERENCES `user` (`user_id`) ON DELETE SET NULL
