INSERT INTO `problem_submissions` VALUES (1,'oaeoae',39,'cacaca',0,'제출해주신 내용은 [JAVA-상] 문자열 순열 생성 문제에 대한 자바 코드라고 보기 어렵습니다. 문제 해결을 위한 로직이나 코드 구현이 전혀 포함되어 있지 않습니다.\n\n**점수:** 0점\n\n**피드백:**\n제출하신 \"cacaca\"는 문자열 순열을 생성하는 자바 코드와는 무관한 내용입니다. 이 문제를 해결하기 위해서는 주어진 문자열의 모든 순열을 중복 없이 생성하여 정렬된 리스트로 반환하는 자바 코드를 작성해야 합니다. 코드 제출 시에는 실제로 동작하는 자바 코드의 형태로 제출해주시기 바랍니다.','2026-04-07 22:21:12',10);
/*!40000 ALTER TABLE `problem_submissions` ENABLE KEYS */;
UNLOCK TABLES;

