INSERT INTO `qna` VALUES (1,'Java에서 NullPointerException 해결 방법은?','NullPointerException이 발생할 때 어떻게 디버깅하면 좋을까요?','user03','2025-08-18 00:35:18','2025-08-18 00:35:18',1,45),(2,'Python 리스트와 튜플 차이점 알려주세요.','리스트와 튜플의 차이점과 사용 예시가 궁금합니다.','user07','2025-08-18 00:35:18','2025-08-18 00:35:18',1,32),(3,'JavaScript 비동기 처리 방법?','Promise와 async/await 중 어떤걸 쓰는 게 좋나요?','user01','2025-08-18 00:35:18','2025-08-18 00:35:18',1,51),(4,'Git에서 브랜치 병합 충돌 해결법','충돌이 났을 때 안전하게 해결하는 팁이 있을까요?','user10','2025-08-18 00:35:18','2026-04-07 19:15:50',1,61),(5,'Spring Boot에서 @Autowired가 안 될 때?','의존성 주입이 제대로 되지 않을 때 점검할 부분이 무엇인가요?','user05','2025-08-18 00:35:18','2025-08-18 00:35:18',1,27),(6,'JPA와 MyBatis 차이점','두 기술의 장단점과 추천 사용 사례를 알고 싶어요.','user09','2025-08-18 00:35:18','2025-08-18 00:35:18',1,38),(7,'코딩 테스트 준비 방법 추천해주세요.','효율적인 문제 풀이 방법과 공부 루틴을 알고 싶어요.','user06','2025-08-18 00:35:18','2025-08-18 00:35:18',0,15),(8,'CSS Flexbox와 Grid 차이점','레이아웃 잡을 때 Flexbox와 Grid 중 언제 어떤걸 쓰면 좋나요?','user02','2025-08-18 00:35:18','2025-08-18 00:35:18',1,40),(9,'Python에서 딕셔너리 키 순서 보장되나요?','Python 3.7 이상에서 딕셔너리 키 순서가 유지되는지 궁금합니다.','user08','2025-08-18 00:35:18','2025-08-18 00:35:18',0,20),(10,'REST API 설계 원칙','좋은 REST API를 설계하기 위한 기본 원칙은 무엇인가요?','user04','2025-08-18 00:35:18','2026-04-04 04:56:54',1,56),(11,'Docker 이미지 최적화 방법','이미지 크기를 줄이고 빌드 속도를 높이는 팁이 있을까요?','user01','2025-08-18 00:35:18','2025-08-18 00:35:18',0,22),(12,'React 상태 관리 추천 라이브러리','초보자가 배우기 좋은 상태 관리 라이브러리가 있을까요?','user03','2025-08-18 00:35:18','2025-08-18 00:35:18',1,30),(13,'SQL 인덱스 잘못 사용하면 어떤 문제가?','잘못된 인덱스 사용 시 성능 문제 예시가 궁금해요.','user07','2025-08-18 00:35:18','2026-04-04 04:34:59',1,29);
/*!40000 ALTER TABLE `qna` ENABLE KEYS */;
UNLOCK TABLES;

