INSERT INTO `qna_reply` VALUES (1,1,'NullPointerException은 참조 변수가 null인 상태에서 접근할 때 발생합니다. 디버깅 시 변수 값을 꼼꼼히 체크하세요.','admin','2025-08-18 00:35:18','2025-08-18 00:35:18'),(2,2,'리스트는 변경 가능하지만 튜플은 불변입니다. 튜플은 변경하지 않을 데이터에 적합합니다.','admin','2025-08-18 00:35:18','2025-08-18 00:35:18'),(3,3,'async/await가 가독성 면에서 좋으며, Promise를 더 간단히 사용할 수 있습니다.','admin','2025-08-18 00:35:18','2025-08-18 00:35:18'),(4,4,'충돌 시 `git status`와 `git diff`를 확인하고, 수동으로 충돌 부분을 수정하세요.','admin','2025-08-18 00:35:18','2025-08-18 00:35:18'),(5,5,'@Autowired가 작동하지 않을 땐 컴포넌트 스캔 설정과 빈 등록을 먼저 확인하세요.','admin','2025-08-18 00:35:18','2025-08-18 00:35:18'),(6,6,'JPA는 객체 중심이고 MyBatis는 SQL 중심입니다. 복잡한 쿼리는 MyBatis가 유리합니다.','admin','2025-08-18 00:35:18','2025-08-18 00:35:18'),(7,8,'Flexbox는 1차원 레이아웃, Grid는 2차원 레이아웃에 적합합니다.','admin','2025-08-18 00:35:18','2025-08-18 00:35:18'),(8,10,'REST API는 리소스 기반 URI, HTTP 메서드 활용, 무상태성을 지켜야 합니다.','admin','2025-08-18 00:35:18','2025-08-18 00:35:18'),(9,12,'React의 기본 useState 외에 Redux, Recoil 등이 많이 쓰입니다. 초보자는 Context API도 추천합니다.','admin','2025-08-18 00:35:18','2025-08-18 00:35:18'),(10,13,'잘못된 인덱스는 오히려 쿼리 속도를 늦출 수 있으니 쿼리 실행 계획을 확인하세요.','admin','2025-08-18 00:35:18','2025-08-18 00:35:18');
/*!40000 ALTER TABLE `qna_reply` ENABLE KEYS */;
UNLOCK TABLES;

